import { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface KeyboardEventData {
  key: string;
  code: string;
  altKey: boolean;
  ctrlKey: boolean;
  shiftKey: boolean;
  metaKey: boolean;
  repeat: boolean;
}

export class KeyboardDevice extends Device {
  private keydownHandler?: (event: KeyboardEvent) => void;
  private keyupHandler?: (event: KeyboardEvent) => void;
  private keyPressHandler?: (event: KeyboardEvent) => void;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: false, // Keyboards are always "connected" in browsers
      supportsHighPrecisionTiming: true
    };

    super('keyboard-primary', 'keyboard', capabilities, clock);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    this.keydownHandler = (event: KeyboardEvent) => {
      const data: KeyboardEventData = {
        key: event.key,
        code: event.code,
        altKey: event.altKey,
        ctrlKey: event.ctrlKey,
        shiftKey: event.shiftKey,
        metaKey: event.metaKey,
        repeat: event.repeat
      };
      this.emitEvent('keydown', data);
    };

    this.keyupHandler = (event: KeyboardEvent) => {
      const data: KeyboardEventData = {
        key: event.key,
        code: event.code,
        altKey: event.altKey,
        ctrlKey: event.ctrlKey,
        shiftKey: event.shiftKey,
        metaKey: event.metaKey,
        repeat: event.repeat
      };
      this.emitEvent('keyup', data);
    };

    this.keyPressHandler = (event: KeyboardEvent) => {
      const data: KeyboardEventData = {
        key: event.key,
        code: event.code,
        altKey: event.altKey,
        ctrlKey: event.ctrlKey,
        shiftKey: event.shiftKey,
        metaKey: event.metaKey,
        repeat: event.repeat
      };
      this.emitEvent('keypress', data);
    };

    document.addEventListener('keydown', this.keydownHandler, { passive: true });
    document.addEventListener('keyup', this.keyupHandler, { passive: true });
    document.addEventListener('keypress', this.keyPressHandler, { passive: true });

    this.setConnected(true);
  }

  async cleanup(): Promise<void> {
    if (this.keydownHandler) {
      document.removeEventListener('keydown', this.keydownHandler);
    }
    if (this.keyupHandler) {
      document.removeEventListener('keyup', this.keyupHandler);
    }
    if (this.keyPressHandler) {
      document.removeEventListener('keypress', this.keyPressHandler);
    }

    this.keydownHandler = undefined;
    this.keyupHandler = undefined;
    this.keyPressHandler = undefined;

    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    // Keyboard capabilities are static in browser environment
    return this.capabilities;
  }

  isKeyPressed(key: string): boolean {
    // Browser doesn't provide a way to check current key state
    // This would need to be tracked internally if required
    throw new Error('Key state tracking not implemented. Use event listeners instead.');
  }
}

