    if (this._isConnected) {
      return;
    }

    this.clickHandler = (event: MouseEvent) => {
      const data: MouseEventData = {
        x: event.clientX,
        y: event.clientY,
        button: event.button,
        buttons: event.buttons,
        altKey: event.altKey,
        ctrlKey: event.ctrlKey,
        shiftKey: event.shiftKey,
