        x: event.clientX,
        y: event.clientY,
        buttons: event.buttons,
        altKey: event.altKey,
        ctrlKey: event.ctrlKey,
        shiftKey: event.shiftKey,
        metaKey: event.metaKey
      };
      this.emitEvent('mousemove', data);
    };

    this.wheelHandler = (event: WheelEvent) => {
