import { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface VideoDeviceInfo {
  deviceId: string;
  label: string;
  facingMode?: 'user' | 'environment';
  resolution?: {
    width: number;
    height: number;
  };
}

export interface VideoEventData {
  width?: number;
  height?: number;
  frameRate?: number;
  stream?: MediaStream;
}

export class VideoDevice extends Device {
  private mediaStream?: MediaStream;
  private videoElement?: HTMLVideoElement;
  private isRecording: boolean = false;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      supportedFormats: ['video/webm', 'video/mp4']
    };

    super('video-primary', 'video', capabilities, clock);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    // Check if video is supported
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      throw new Error('Video capture not supported on this device');
    }

    this.setConnected(true);

    // Monitor device changes
    navigator.mediaDevices.addEventListener('devicechange', this.handleDeviceChange.bind(this));
  }

  async cleanup(): Promise<void> {
    await this.stopCapture();

    if (this.videoElement) {
      this.videoElement.pause();
      this.videoElement.srcObject = null;
      this.videoElement = undefined;
    }

    navigator.mediaDevices?.removeEventListener('devicechange', this.handleDeviceChange.bind(this));

    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      return {
        canDetectHotplug: false,
        supportsHighPrecisionTiming: false,
        supportedFormats: []
      };
    }

    const devices = await this.getVideoDevices();
    const hasCamera = devices.length > 0;

    return {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      supportedFormats: hasCamera ? ['video/webm', 'video/mp4'] : []
    };
  }

  async getVideoDevices(): Promise<VideoDeviceInfo[]> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      return [];
    }

    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      return devices
        .filter(device => device.kind === 'videoinput')
        .map(device => ({
          deviceId: device.deviceId,
          label: device.label,
          facingMode: this.inferFacingMode(device.label)
        }));
    } catch (error) {
      console.error('Error enumerating video devices:', error);
      return [];
    }
  }

  async startCapture(
    deviceId?: string,
    constraints?: {
      width?: number;
      height?: number;
      frameRate?: number;
      facingMode?: 'user' | 'environment';
    }
  ): Promise<MediaStream> {
    if (this.isRecording) {
      throw new Error('Video capture already active');
    }

    try {
      const videoConstraints: MediaTrackConstraints = {
        ...constraints
      };

      if (deviceId) {
        videoConstraints.deviceId = { exact: deviceId };
      }

      const mediaConstraints: MediaStreamConstraints = {
        video: videoConstraints,
        audio: false
      };

      this.mediaStream = await navigator.mediaDevices.getUserMedia(mediaConstraints);
      this.isRecording = true;

      // Get actual video settings
      const videoTrack = this.mediaStream.getVideoTracks()[0];
      const settings = videoTrack.getSettings();

