// Core device abstractions
export { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
export { DeviceManager, DeviceManagerOptions, DeviceType } from './DeviceManager.js';

// Input devices
export { KeyboardDevice, KeyboardEventData } from './KeyboardDevice.js';
export { MouseDevice, MouseEventData } from './MouseDevice.js';
export { TouchDevice, TouchEventData, TouchPoint, OrientationEventData } from './TouchDevice.js';

// Audio/video devices
export { AudioDevice, AudioDeviceInfo, AudioEventData } from './AudioDevice.js';
export { VideoDevice, VideoDeviceInfo, VideoEventData } from './VideoDevice.js';

// Helper functions for common device management patterns
export function createDeviceManager(
  clock: import('@psyforge/timing').PrecisionClock,
  options?: DeviceManagerOptions
): DeviceManager {
  return new DeviceManager(clock, options);
}

export async function detectDeviceCapabilities(
  clock: import('@psyforge/timing').PrecisionClock
): Promise<{
  keyboard: boolean;
  mouse: boolean;
  touch: boolean;
  audio: boolean;
  video: boolean;
}> {
  const manager = createDeviceManager(clock, { enableAutoDetection: false });
  return await manager.detectAvailableDevices();
}

// Type guards for device instances
export function isKeyboardDevice(device: Device): device is KeyboardDevice {
  return device.deviceType === 'keyboard';
}

export function isMouseDevice(device: Device): device is MouseDevice {
  return device.deviceType === 'mouse';
}

export function isTouchDevice(device: Device): device is TouchDevice {
  return device.deviceType === 'touch';
}

export function isAudioDevice(device: Device): device is AudioDevice {
  return device.deviceType === 'audio';
}

export function isVideoDevice(device: Device): device is VideoDevice {
  return device.deviceType === 'video';
}

