import { describe, it, expect, vi, beforeEach } from 'vitest';
import { Device, DeviceCapabilities, DeviceEvent } from '../src/Device.js';
import type { PrecisionClock } from '@psyforge/timing';

class TestDevice extends Device {
  async initialize(): Promise<void> {
    this.setConnected(true);
  }

  async cleanup(): Promise<void> {
    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    return this.capabilities;
  }

  // Expose protected methods for testing
  public testEmitEvent<T>(eventType: string, data: T): void {
    this.emitEvent(eventType, data);
  }

  public testSetConnected(connected: boolean): void {
    this.setConnected(connected);
  }
}

describe('Device', () => {
  let mockClock: PrecisionClock;
  let device: TestDevice;
  let capabilities: DeviceCapabilities;

  beforeEach(() => {
    mockClock = {
      now: vi.fn().mockReturnValue(1000.123)
    } as any;

    capabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      maxSampleRate: 48000
    };

    device = new TestDevice('test-device', 'test', capabilities, mockClock);
  });

  describe('constructor', () => {
    it('should initialize with correct properties', () => {
      expect(device.id).toBe('test-device');
      expect(device.deviceType).toBe('test');
      expect(device.isConnected).toBe(false);
      expect(device.capabilities).toEqual(capabilities);
    });

    it('should return a copy of capabilities to prevent mutation', () => {
      const caps = device.capabilities;
      caps.canDetectHotplug = false;
      expect(device.capabilities.canDetectHotplug).toBe(true);
    });
  });

  describe('event handling', () => {
    it('should add and remove event listeners', () => {
      const callback = vi.fn();

      device.addEventListener('test-event', callback);
      device.testEmitEvent('test-event', { test: 'data' });

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'test-event',
        deviceId: 'test-device',
        data: { test: 'data' }
      });

      device.removeEventListener('test-event', callback);
      device.testEmitEvent('test-event', { test: 'data2' });

      expect(callback).toHaveBeenCalledTimes(1);
    });

    it('should handle multiple listeners for same event', () => {
      const callback1 = vi.fn();
      const callback2 = vi.fn();

      device.addEventListener('test-event', callback1);
      device.addEventListener('test-event', callback2);
      device.testEmitEvent('test-event', { test: 'data' });

      expect(callback1).toHaveBeenCalledTimes(1);
      expect(callback2).toHaveBeenCalledTimes(1);
    });

    it('should handle listener errors gracefully', () => {
      const errorCallback = vi.fn().mockImplementation(() => {
        throw new Error('Listener error');
      });
      const goodCallback = vi.fn();

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      device.addEventListener('test-event', errorCallback);
      device.addEventListener('test-event', goodCallback);
      device.testEmitEvent('test-event', { test: 'data' });

      expect(errorCallback).toHaveBeenCalledTimes(1);
      expect(goodCallback).toHaveBeenCalledTimes(1);
      expect(consoleSpy).toHaveBeenCalledWith(
        'Error in device event listener for test-event:',
        expect.any(Error)
      );

      consoleSpy.mockRestore();
    });

    it('should clean up empty listener sets', () => {
      const callback = vi.fn();

      device.addEventListener('test-event', callback);
      device.removeEventListener('test-event', callback);

      // Should not emit anything after removal
      device.testEmitEvent('test-event', { test: 'data' });
      expect(callback).not.toHaveBeenCalled();
    });
  });

  describe('connection state', () => {
    it('should emit connection events when state changes', () => {
      const connectedCallback = vi.fn();
      const disconnectedCallback = vi.fn();

      device.addEventListener('connected', connectedCallback);
      device.addEventListener('disconnected', disconnectedCallback);

      device.testSetConnected(true);
      expect(device.isConnected).toBe(true);
      expect(connectedCallback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'connected',
        deviceId: 'test-device',
        data: { connected: true }
      });

      device.testSetConnected(false);
      expect(device.isConnected).toBe(false);
      expect(disconnectedCallback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'disconnected',
        deviceId: 'test-device',
        data: { connected: false }
      });
    });

    it('should not emit events when connection state does not change', () => {
      const callback = vi.fn();
      device.addEventListener('connected', callback);

      device.testSetConnected(false); // Already false
      device.testSetConnected(false); // Still false

      expect(callback).not.toHaveBeenCalled();
    });
  });

  describe('initialization and cleanup', () => {
    it('should initialize successfully', async () => {
      await device.initialize();
      expect(device.isConnected).toBe(true);
    });

    it('should cleanup successfully', async () => {
      await device.initialize();
      await device.cleanup();
      expect(device.isConnected).toBe(false);
    });

    it('should detect capabilities', async () => {
      const caps = await device.detectCapabilities();
      expect(caps).toEqual(capabilities);
    });
  });

  describe('timing integration', () => {
    it('should use precision clock for event timestamps', () => {
      const callback = vi.fn();
      device.addEventListener('test-event', callback);

      (mockClock.now as any).mockReturnValue(2000.456);
      device.testEmitEvent('test-event', { test: 'data' });

      expect(callback).toHaveBeenCalledWith(
        expect.objectContaining({
          timestamp: 2000.456
        })
      );
    });
  });
});

