import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { KeyboardDevice, KeyboardEventData } from '../src/KeyboardDevice.js';
import type { PrecisionClock } from '@psyforge/timing';

describe('KeyboardDevice', () => {
  let mockClock: PrecisionClock;
  let keyboardDevice: KeyboardDevice;
  let addEventListenerSpy: any;
  let removeEventListenerSpy: any;

  beforeEach(() => {
    mockClock = {
      now: vi.fn().mockReturnValue(1000.123)
    } as any;

    keyboardDevice = new KeyboardDevice(mockClock);

    // Mock document event listeners
    addEventListenerSpy = vi.spyOn(document, 'addEventListener');
    removeEventListenerSpy = vi.spyOn(document, 'removeEventListener');
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('should initialize with correct properties', () => {
      expect(keyboardDevice.id).toBe('keyboard-primary');
      expect(keyboardDevice.deviceType).toBe('keyboard');
      expect(keyboardDevice.isConnected).toBe(false);
      expect(keyboardDevice.capabilities).toEqual({
        canDetectHotplug: false,
        supportsHighPrecisionTiming: true
      });
    });
  });

  describe('initialization', () => {
    it('should initialize and attach event listeners', async () => {
      await keyboardDevice.initialize();

      expect(keyboardDevice.isConnected).toBe(true);
      expect(addEventListenerSpy).toHaveBeenCalledWith('keydown', expect.any(Function), { passive: true });
      expect(addEventListenerSpy).toHaveBeenCalledWith('keyup', expect.any(Function), { passive: true });
      expect(addEventListenerSpy).toHaveBeenCalledWith('keypress', expect.any(Function), { passive: true });
      expect(addEventListenerSpy).toHaveBeenCalledTimes(3);
    });

    it('should not reinitialize if already connected', async () => {
      await keyboardDevice.initialize();
      addEventListenerSpy.mockClear();

      await keyboardDevice.initialize();
      expect(addEventListenerSpy).not.toHaveBeenCalled();
    });
  });

  describe('cleanup', () => {
    it('should cleanup and remove event listeners', async () => {
      await keyboardDevice.initialize();
      await keyboardDevice.cleanup();

      expect(keyboardDevice.isConnected).toBe(false);
      expect(removeEventListenerSpy).toHaveBeenCalledWith('keydown', expect.any(Function));
      expect(removeEventListenerSpy).toHaveBeenCalledWith('keyup', expect.any(Function));
      expect(removeEventListenerSpy).toHaveBeenCalledWith('keypress', expect.any(Function));
      expect(removeEventListenerSpy).toHaveBeenCalledTimes(3);
    });

    it('should handle cleanup when not initialized', async () => {
      await keyboardDevice.cleanup();
      expect(removeEventListenerSpy).not.toHaveBeenCalled();
    });
  });

  describe('event handling', () => {
    beforeEach(async () => {
      await keyboardDevice.initialize();
    });

    it('should emit keydown events', async () => {
      const callback = vi.fn();
      keyboardDevice.addEventListener('keydown', callback);

      // Simulate keydown event
      const mockEvent = new KeyboardEvent('keydown', {
        key: 'a',
        code: 'KeyA',
        altKey: false,
        ctrlKey: true,
        shiftKey: false,
        metaKey: false,
        repeat: false
      });

      // Get the registered handler and call it
      const keydownHandler = addEventListenerSpy.mock.calls
        .find(call => call[0] === 'keydown')[1];
      keydownHandler(mockEvent);

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'keydown',
        deviceId: 'keyboard-primary',
        data: {
          key: 'a',
          code: 'KeyA',
          altKey: false,
          ctrlKey: true,
          shiftKey: false,
          metaKey: false,
          repeat: false
        }
      });
    });

    it('should emit keyup events', async () => {
      const callback = vi.fn();
      keyboardDevice.addEventListener('keyup', callback);

      const mockEvent = new KeyboardEvent('keyup', {
        key: 'Escape',
        code: 'Escape',
        altKey: true,
        ctrlKey: false,
        shiftKey: true,
        metaKey: false,
        repeat: false
      });

      const keyupHandler = addEventListenerSpy.mock.calls
        .find(call => call[0] === 'keyup')[1];
      keyupHandler(mockEvent);

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'keyup',
        deviceId: 'keyboard-primary',
        data: {
          key: 'Escape',
          code: 'Escape',
          altKey: true,
          ctrlKey: false,
          shiftKey: true,
          metaKey: false,
          repeat: false
        }
      });
    });

    it('should emit keypress events', async () => {
      const callback = vi.fn();
      keyboardDevice.addEventListener('keypress', callback);

      const mockEvent = new KeyboardEvent('keypress', {
        key: 'Enter',
        code: 'Enter',
        altKey: false,
        ctrlKey: false,
        shiftKey: false,
        metaKey: true,
        repeat: true
      });

      const keypressHandler = addEventListenerSpy.mock.calls
        .find(call => call[0] === 'keypress')[1];
      keypressHandler(mockEvent);

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'keypress',
        deviceId: 'keyboard-primary',
        data: {
          key: 'Enter',
          code: 'Enter',
          altKey: false,
          ctrlKey: false,
          shiftKey: false,
          metaKey: true,
          repeat: true
        }
      });
    });
  });

  describe('capabilities detection', () => {
    it('should return static capabilities', async () => {
      const capabilities = await keyboardDevice.detectCapabilities();
      expect(capabilities).toEqual({
        canDetectHotplug: false,
        supportsHighPrecisionTiming: true
      });
    });
  });

  describe('key state tracking', () => {
    it('should throw error for isKeyPressed method', () => {
      expect(() => keyboardDevice.isKeyPressed('a')).toThrow(
        'Key state tracking not implemented. Use event listeners instead.'
      );
    });
  });
});

