        { kind: 'videoinput', deviceId: 'video1' }
      ]);

      const available = await deviceManager.detectAvailableDevices();

      expect(available).toEqual({
        keyboard: true,
        mouse: true,
        touch: false,
        audio: true,
        video: true
      });
    });

    it('should handle device enumeration errors', async () => {
      (navigator.mediaDevices.enumerateDevices as any).mockRejectedValue(new Error('Enum failed'));

      const available = await deviceManager.detectAvailableDevices();

      expect(available.audio).toBe(false);
      expect(available.video).toBe(false);
    });

    it('should detect touch support', async () => {
      Object.defineProperty(window, 'ontouchstart', {
        value: {},
        configurable: true
      });

      const available = await deviceManager.detectAvailableDevices();
      expect(available.touch).toBe(true);
    });
  });

  describe('event forwarding', () => {
    beforeEach(async () => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard']
      });
      await deviceManager.initialize();
    });

    it('should forward device events', () => {
      const callback = vi.fn();
      deviceManager.addEventListener('keydown', callback);

      // Simulate device event
      const eventCallback = mockKeyboard.addEventListener.mock.calls
        .find(call => call[0] === 'keydown')[1];

      const deviceEvent = {
        timestamp: 1000.123,
        type: 'keydown',
        deviceId: 'keyboard-primary',
        data: { key: 'a' }
      };

      eventCallback(deviceEvent);

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'keydown',
        deviceId: 'manager',
        data: { key: 'a' }
      });
    });

    it('should emit deviceadded event when device is added', async () => {
      const callback = vi.fn();

      const newManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard']
      });
      newManager.addEventListener('deviceadded', callback);

      await newManager.initialize();

      expect(callback).toHaveBeenCalledWith({
