import { describe, it, expect, vi } from 'vitest';
import {
  Device,
  DeviceManager,
  KeyboardDevice,
  MouseDevice,
  TouchDevice,
  AudioDevice,
  VideoDevice,
  createDeviceManager,
  detectDeviceCapabilities,
  isKeyboardDevice,
  isMouseDevice,
  isTouchDevice,
  isAudioDevice,
  isVideoDevice
} from '../src/index.js';
import type { PrecisionClock } from '@psyforge/timing';

describe('Index exports', () => {
  let mockClock: PrecisionClock;

  beforeEach(() => {
    mockClock = {
      now: vi.fn().mockReturnValue(1000.123)
    } as any;

    // Mock navigator.mediaDevices
    Object.defineProperty(navigator, 'mediaDevices', {
      value: {
        getUserMedia: vi.fn(),
        enumerateDevices: vi.fn().mockResolvedValue([])
      },
      configurable: true
    });
  });

  describe('exports', () => {
    it('should export all device classes', () => {
      expect(Device).toBeDefined();
      expect(DeviceManager).toBeDefined();
      expect(KeyboardDevice).toBeDefined();
      expect(MouseDevice).toBeDefined();
      expect(TouchDevice).toBeDefined();
      expect(AudioDevice).toBeDefined();
      expect(VideoDevice).toBeDefined();
    });

    it('should export helper functions', () => {
      expect(createDeviceManager).toBeTypeOf('function');
      expect(detectDeviceCapabilities).toBeTypeOf('function');
    });

    it('should export type guards', () => {
      expect(isKeyboardDevice).toBeTypeOf('function');
      expect(isMouseDevice).toBeTypeOf('function');
      expect(isTouchDevice).toBeTypeOf('function');
      expect(isAudioDevice).toBeTypeOf('function');
      expect(isVideoDevice).toBeTypeOf('function');
    });
  });

  describe('createDeviceManager', () => {
    it('should create a device manager with default options', () => {
      const manager = createDeviceManager(mockClock);
      expect(manager).toBeInstanceOf(DeviceManager);
    });

    it('should create a device manager with custom options', () => {
      const options = { enabledDevices: ['keyboard'] as const };
      const manager = createDeviceManager(mockClock, options);
      expect(manager).toBeInstanceOf(DeviceManager);
    });
  });

  describe('detectDeviceCapabilities', () => {
    it('should detect device capabilities', async () => {
      const capabilities = await detectDeviceCapabilities(mockClock);

      expect(capabilities).toHaveProperty('keyboard');
      expect(capabilities).toHaveProperty('mouse');
      expect(capabilities).toHaveProperty('touch');
