import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { DeviceManager, DeviceManagerOptions } from '../src/DeviceManager.js';
import { KeyboardDevice } from '../src/KeyboardDevice.js';
import { MouseDevice } from '../src/MouseDevice.js';
import type { PrecisionClock } from '@psyforge/timing';

// Mock the device classes
vi.mock('../src/KeyboardDevice.js');
vi.mock('../src/MouseDevice.js');
vi.mock('../src/TouchDevice.js');
vi.mock('../src/AudioDevice.js');
vi.mock('../src/VideoDevice.js');

describe('DeviceManager', () => {
  let mockClock: PrecisionClock;
  let deviceManager: DeviceManager;
  let mockKeyboard: any;
  let mockMouse: any;

  beforeEach(() => {
    mockClock = {
      now: vi.fn().mockReturnValue(1000.123)
    } as any;

    // Reset mocks
    vi.clearAllMocks();

    // Mock device instances
    mockKeyboard = {
      id: 'keyboard-primary',
      deviceType: 'keyboard',
      isConnected: true,
      capabilities: { canDetectHotplug: false, supportsHighPrecisionTiming: true },
      initialize: vi.fn().mockResolvedValue(undefined),
      cleanup: vi.fn().mockResolvedValue(undefined),
      addEventListener: vi.fn(),
      detectCapabilities: vi.fn().mockResolvedValue({ canDetectHotplug: false, supportsHighPrecisionTiming: true })
    };

    mockMouse = {
      id: 'mouse-primary',
      deviceType: 'mouse',
      isConnected: true,
      capabilities: { canDetectHotplug: false, supportsHighPrecisionTiming: true },
      initialize: vi.fn().mockResolvedValue(undefined),
      cleanup: vi.fn().mockResolvedValue(undefined),
      addEventListener: vi.fn(),
      detectCapabilities: vi.fn().mockResolvedValue({ canDetectHotplug: false, supportsHighPrecisionTiming: true })
    };

    // Mock constructors
    (KeyboardDevice as any).mockImplementation(() => mockKeyboard);
    (MouseDevice as any).mockImplementation(() => mockMouse);

    // Mock navigator.mediaDevices
    Object.defineProperty(navigator, 'mediaDevices', {
      value: {
        getUserMedia: vi.fn(),
        enumerateDevices: vi.fn().mockResolvedValue([])
      },
      configurable: true
    });

    // Mock touch support
    Object.defineProperty(window, 'ontouchstart', {
      value: undefined,
      configurable: true
    });
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('should initialize with default options', () => {
      deviceManager = new DeviceManager(mockClock);
      expect(deviceManager).toBeDefined();
    });

    it('should initialize with custom options', () => {
      const options: DeviceManagerOptions = {
        enableAutoDetection: false,
        enabledDevices: ['keyboard', 'mouse']
      };
      deviceManager = new DeviceManager(mockClock, options);
      expect(deviceManager).toBeDefined();
    });
  });

  describe('initialization', () => {
    beforeEach(() => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard', 'mouse']
      });
    });

    it('should initialize enabled devices', async () => {
      await deviceManager.initialize();

      expect(KeyboardDevice).toHaveBeenCalledWith(mockClock);
      expect(MouseDevice).toHaveBeenCalledWith(mockClock);
      expect(mockKeyboard.initialize).toHaveBeenCalled();
      expect(mockMouse.initialize).toHaveBeenCalled();
    });

    it('should handle device initialization failures gracefully', async () => {
      mockKeyboard.initialize.mockRejectedValue(new Error('Keyboard init failed'));

      const consoleSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});

      await deviceManager.initialize();

      expect(consoleSpy).toHaveBeenCalledWith(
        'Failed to initialize keyboard device:',
        expect.any(Error)
      );

      consoleSpy.mockRestore();
    });

    it('should emit managerready event after initialization', async () => {
      const callback = vi.fn();
      deviceManager.addEventListener('managerready', callback);

      await deviceManager.initialize();

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'managerready',
        deviceId: 'manager',
        data: {
          deviceCount: 2,
          devices: ['keyboard-primary', 'mouse-primary']
        }
      });
    });
  });

  describe('cleanup', () => {
    beforeEach(async () => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard', 'mouse']
      });
      await deviceManager.initialize();
    });

    it('should cleanup all devices', async () => {
      await deviceManager.cleanup();

      expect(mockKeyboard.cleanup).toHaveBeenCalled();
      expect(mockMouse.cleanup).toHaveBeenCalled();
    });

    it('should handle cleanup errors gracefully', async () => {
      mockKeyboard.cleanup.mockRejectedValue(new Error('Cleanup failed'));

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      await deviceManager.cleanup();

      expect(consoleSpy).toHaveBeenCalledWith(
        'Error cleaning up device keyboard-primary:',
        expect.any(Error)
      );

      consoleSpy.mockRestore();
    });
  });

  describe('device access', () => {
    beforeEach(async () => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard', 'mouse']
      });
      await deviceManager.initialize();
    });

    it('should get device by ID', () => {
      const device = deviceManager.getDevice('keyboard-primary');
      expect(device).toBe(mockKeyboard);
    });

    it('should return undefined for non-existent device', () => {
      const device = deviceManager.getDevice('non-existent');
      expect(device).toBeUndefined();
    });

    it('should get devices by type', () => {
      const keyboards = deviceManager.getDevicesByType('keyboard');
      expect(keyboards).toHaveLength(1);
      expect(keyboards[0]).toBe(mockKeyboard);
    });

    it('should get all devices', () => {
      const devices = deviceManager.getAllDevices();
      expect(devices).toHaveLength(2);
      expect(devices).toContain(mockKeyboard);
      expect(devices).toContain(mockMouse);
    });

    it('should get connected devices', () => {
      const connected = deviceManager.getConnectedDevices();
      expect(connected).toHaveLength(2);
    });
  });

  describe('capabilities detection', () => {
    beforeEach(async () => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard']
      });
      await deviceManager.initialize();
    });

    it('should get device capabilities', async () => {
      const capabilities = await deviceManager.getDeviceCapabilities('keyboard-primary');
      expect(capabilities).toEqual({
        canDetectHotplug: false,
        supportsHighPrecisionTiming: true
      });
    });

    it('should return null for non-existent device', async () => {
      const capabilities = await deviceManager.getDeviceCapabilities('non-existent');
      expect(capabilities).toBeNull();
    });

    it('should handle capability detection errors', async () => {
      mockKeyboard.detectCapabilities.mockRejectedValue(new Error('Detection failed'));

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      const capabilities = await deviceManager.getDeviceCapabilities('keyboard-primary');

      expect(capabilities).toBeNull();
      expect(consoleSpy).toHaveBeenCalledWith(
        'Error detecting capabilities for device keyboard-primary:',
        expect.any(Error)
      );

      consoleSpy.mockRestore();
    });
  });

  describe('available device detection', () => {
    beforeEach(() => {
      deviceManager = new DeviceManager(mockClock);
    });

    it('should detect available devices', async () => {
      (navigator.mediaDevices.enumerateDevices as any).mockResolvedValue([
        { kind: 'audioinput', deviceId: 'audio1' },
        { kind: 'videoinput', deviceId: 'video1' }
      ]);

      const available = await deviceManager.detectAvailableDevices();

      expect(available).toEqual({
        keyboard: true,
        mouse: true,
        touch: false,
        audio: true,
        video: true
      });
    });

    it('should handle device enumeration errors', async () => {
      (navigator.mediaDevices.enumerateDevices as any).mockRejectedValue(new Error('Enum failed'));

      const available = await deviceManager.detectAvailableDevices();

      expect(available.audio).toBe(false);
      expect(available.video).toBe(false);
    });

    it('should detect touch support', async () => {
      Object.defineProperty(window, 'ontouchstart', {
        value: {},
        configurable: true
      });

      const available = await deviceManager.detectAvailableDevices();
      expect(available.touch).toBe(true);
    });
  });

  describe('event forwarding', () => {
    beforeEach(async () => {
      deviceManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard']
      });
      await deviceManager.initialize();
    });

    it('should forward device events', () => {
      const callback = vi.fn();
      deviceManager.addEventListener('keydown', callback);

      // Simulate device event
      const eventCallback = mockKeyboard.addEventListener.mock.calls
        .find(call => call[0] === 'keydown')[1];

      const deviceEvent = {
        timestamp: 1000.123,
        type: 'keydown',
        deviceId: 'keyboard-primary',
        data: { key: 'a' }
      };

      eventCallback(deviceEvent);

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'keydown',
        deviceId: 'manager',
        data: { key: 'a' }
      });
    });

    it('should emit deviceadded event when device is added', async () => {
      const callback = vi.fn();

      const newManager = new DeviceManager(mockClock, {
        enabledDevices: ['keyboard']
      });
      newManager.addEventListener('deviceadded', callback);

      await newManager.initialize();

      expect(callback).toHaveBeenCalledWith({
        timestamp: 1000.123,
        type: 'deviceadded',
        deviceId: 'manager',
        data: {
          deviceId: 'keyboard-primary',
          deviceType: 'keyboard',
          isConnected: true
        }
      });
    });
  });
});

