import { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
import { KeyboardDevice } from './KeyboardDevice.js';
import { MouseDevice } from './MouseDevice.js';
import { TouchDevice } from './TouchDevice.js';
import { AudioDevice } from './AudioDevice.js';
import { VideoDevice } from './VideoDevice.js';
import type { PrecisionClock } from '@psyforge/timing';

export type DeviceType = 'keyboard' | 'mouse' | 'touch' | 'audio' | 'video';

export interface DeviceManagerOptions {
  enableAutoDetection?: boolean;
  enabledDevices?: DeviceType[];
}

export class DeviceManager {
  private devices: Map<string, Device> = new Map();
  private eventListeners: Map<string, Set<(event: DeviceEvent) => void>> = new Map();
  private clock: PrecisionClock;
  private options: Required<DeviceManagerOptions>;

  constructor(clock: PrecisionClock, options: DeviceManagerOptions = {}) {
    this.clock = clock;
    this.options = {
      enableAutoDetection: options.enableAutoDetection ?? true,
      enabledDevices: options.enabledDevices ?? ['keyboard', 'mouse', 'touch', 'audio', 'video']
    };
  }

  async initialize(): Promise<void> {
    // Initialize enabled devices
    const devicePromises: Promise<void>[] = [];

    if (this.options.enabledDevices.includes('keyboard')) {
      devicePromises.push(this.initializeKeyboard());
    }

    if (this.options.enabledDevices.includes('mouse')) {
      devicePromises.push(this.initializeMouse());
    }

    if (this.options.enabledDevices.includes('touch')) {
      devicePromises.push(this.initializeTouch());
    }

    if (this.options.enabledDevices.includes('audio')) {
      devicePromises.push(this.initializeAudio());
    }

    if (this.options.enabledDevices.includes('video')) {
      devicePromises.push(this.initializeVideo());
    }

    // Wait for all devices to initialize (some may fail)
    await Promise.allSettled(devicePromises);

    this.emitEvent('managerready', { 
      deviceCount: this.devices.size,
      devices: Array.from(this.devices.keys())
    });
  }

  async cleanup(): Promise<void> {
    const cleanupPromises: Promise<void>[] = [];

    for (const device of this.devices.values()) {
      cleanupPromises.push(device.cleanup().catch(error => {
        console.error(`Error cleaning up device ${device.id}:`, error);
      }));
    }

    await Promise.allSettled(cleanupPromises);
    this.devices.clear();
    this.eventListeners.clear();
  }

  getDevice<T extends Device = Device>(deviceId: string): T | undefined {
    return this.devices.get(deviceId) as T | undefined;
  }

  getDevicesByType<T extends Device = Device>(type: DeviceType): T[] {
    return Array.from(this.devices.values())
      .filter(device => device.deviceType === type) as T[];
  }

  getAllDevices(): Device[] {
    return Array.from(this.devices.values());
  }

  getConnectedDevices(): Device[] {
    return Array.from(this.devices.values()).filter(device => device.isConnected);
  }

  async getDeviceCapabilities(deviceId: string): Promise<DeviceCapabilities | null> {
    const device = this.devices.get(deviceId);
    if (!device) {
      return null;
    }

    try {
      return await device.detectCapabilities();
    } catch (error) {
      console.error(`Error detecting capabilities for device ${deviceId}:`, error);
      return null;
    }
  }

  async detectAvailableDevices(): Promise<{
    keyboard: boolean;
    mouse: boolean;
    touch: boolean;
    audio: boolean;
    video: boolean;
  }> {
    const detection = {
      keyboard: true, // Always available in browsers
      mouse: true,    // Always available in browsers
      touch: 'ontouchstart' in window,
      audio: !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia),
      video: !!(navigator.mediaDevices && navigator.mediaDevices.getUserMedia)
    };

    // Verify audio/video by checking for actual devices
    if (detection.audio || detection.video) {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        detection.audio = devices.some(d => d.kind === 'audioinput');
        detection.video = devices.some(d => d.kind === 'videoinput');
      } catch (error) {
        detection.audio = false;
        detection.video = false;
      }
    }

    return detection;
  }

  addEventListener<T = any>(
    eventType: string, 
    callback: (event: DeviceEvent<T>) => void
  ): void {
    if (!this.eventListeners.has(eventType)) {
      this.eventListeners.set(eventType, new Set());
    }
    this.eventListeners.get(eventType)!.add(callback as (event: DeviceEvent) => void);
  }

  removeEventListener<T = any>(
    eventType: string, 
    callback: (event: DeviceEvent<T>) => void
  ): void {
    const listeners = this.eventListeners.get(eventType);
    if (listeners) {
      listeners.delete(callback as (event: DeviceEvent) => void);
      if (listeners.size === 0) {
        this.eventListeners.delete(eventType);
      }
    }
  }

  private async initializeKeyboard(): Promise<void> {
    try {
      const keyboard = new KeyboardDevice(this.clock);
      await keyboard.initialize();
      this.addDevice(keyboard);
    } catch (error) {
      console.warn('Failed to initialize keyboard device:', error);
    }
  }

  private async initializeMouse(): Promise<void> {
    try {
      const mouse = new MouseDevice(this.clock);
      await mouse.initialize();
      this.addDevice(mouse);
    } catch (error) {
      console.warn('Failed to initialize mouse device:', error);
    }
  }

  private async initializeTouch(): Promise<void> {
    if (!('ontouchstart' in window)) {
      return; // Touch not supported
    }

    try {
      const touch = new TouchDevice(this.clock);
      await touch.initialize();
      this.addDevice(touch);
    } catch (error) {
      console.warn('Failed to initialize touch device:', error);
    }
  }

  private async initializeAudio(): Promise<void> {
    try {
      const audio = new AudioDevice(this.clock);
      await audio.initialize();
      this.addDevice(audio);
    } catch (error) {
      console.warn('Failed to initialize audio device:', error);
    }
  }

  private async initializeVideo(): Promise<void> {
    try {
      const video = new VideoDevice(this.clock);
      await video.initialize();
      this.addDevice(video);
    } catch (error) {
      console.warn('Failed to initialize video device:', error);
    }
  }

  private addDevice(device: Device): void {
    this.devices.set(device.id, device);

    // Forward all device events to manager listeners
    const forwardEvent = (event: DeviceEvent) => {
      this.emitEvent(event.type, event.data);
      this.emitEvent('deviceevent', event);
    };

    // Listen to all possible device events
    device.addEventListener('connected', forwardEvent);
    device.addEventListener('disconnected', forwardEvent);
    device.addEventListener('error', forwardEvent);

    // Device-specific events
    if (device instanceof KeyboardDevice) {
      device.addEventListener('keydown', forwardEvent);
      device.addEventListener('keyup', forwardEvent);
      device.addEventListener('keypress', forwardEvent);
    }

    if (device instanceof MouseDevice) {
      device.addEventListener('click', forwardEvent);
      device.addEventListener('mousedown', forwardEvent);
      device.addEventListener('mouseup', forwardEvent);
      device.addEventListener('mousemove', forwardEvent);
      device.addEventListener('wheel', forwardEvent);
      device.addEventListener('contextmenu', forwardEvent);
    }

    if (device instanceof TouchDevice) {
      device.addEventListener('touchstart', forwardEvent);
      device.addEventListener('touchmove', forwardEvent);
      device.addEventListener('touchend', forwardEvent);
      device.addEventListener('touchcancel', forwardEvent);
      device.addEventListener('deviceorientation', forwardEvent);
    }

    if (device instanceof AudioDevice) {
      device.addEventListener('recordingstarted', forwardEvent);
      device.addEventListener('recordingstopped', forwardEvent);
      device.addEventListener('soundplayed', forwardEvent);
      device.addEventListener('toneplayed', forwardEvent);
      device.addEventListener('audiolevel', forwardEvent);
      device.addEventListener('devicechange', forwardEvent);
    }

    if (device instanceof VideoDevice) {
      device.addEventListener('capturestarted', forwardEvent);
      device.addEventListener('capturestopped', forwardEvent);
      device.addEventListener('videoelement', forwardEvent);
      device.addEventListener('phototaken', forwardEvent);
      device.addEventListener('devicechange', forwardEvent);
    }

    this.emitEvent('deviceadded', { 
      deviceId: device.id, 
      deviceType: device.deviceType,
      isConnected: device.isConnected 
    });
  }

  private emitEvent<T = any>(eventType: string, data: T): void {
    const listeners = this.eventListeners.get(eventType);
    if (listeners && listeners.size > 0) {
      const event: DeviceEvent<T> = {
        timestamp: this.clock.now(),
        type: eventType,
        deviceId: 'manager',
        data
      };

      listeners.forEach(callback => {
        try {
          callback(event);
        } catch (error) {
          console.error(`Error in device manager event listener for ${eventType}:`, error);
        }
      });
    }
  }
}

