import { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface TouchPoint {
  identifier: number;
  x: number;
  y: number;
  radiusX?: number;
  radiusY?: number;
  rotationAngle?: number;
  force?: number;
}

export interface TouchEventData {
  touches: TouchPoint[];
  changedTouches: TouchPoint[];
  targetTouches: TouchPoint[];
  altKey: boolean;
  ctrlKey: boolean;
  shiftKey: boolean;
  metaKey: boolean;
}

export interface OrientationEventData {
  alpha: number | null;
  beta: number | null;
  gamma: number | null;
  absolute: boolean;
}

export class TouchDevice extends Device {
  private touchstartHandler?: (event: TouchEvent) => void;
  private touchmoveHandler?: (event: TouchEvent) => void;
  private touchendHandler?: (event: TouchEvent) => void;
  private touchcancelHandler?: (event: TouchEvent) => void;
  private orientationHandler?: (event: DeviceOrientationEvent) => void;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: false,
      supportsHighPrecisionTiming: true,
      hasOrientationSupport: 'DeviceOrientationEvent' in window,
      hasPressureSupport: 'force' in Touch.prototype
    };

    super('touch-primary', 'touch', capabilities, clock);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    // Check if touch is supported
    if (!('ontouchstart' in window)) {
      throw new Error('Touch events not supported on this device');
    }

    this.touchstartHandler = (event: TouchEvent) => {
      const data = this.createTouchEventData(event);
      this.emitEvent('touchstart', data);
    };

    this.touchmoveHandler = (event: TouchEvent) => {
      const data = this.createTouchEventData(event);
      this.emitEvent('touchmove', data);
    };

    this.touchendHandler = (event: TouchEvent) => {
      const data = this.createTouchEventData(event);
      this.emitEvent('touchend', data);
    };

    this.touchcancelHandler = (event: TouchEvent) => {
      const data = this.createTouchEventData(event);
      this.emitEvent('touchcancel', data);
    };

    document.addEventListener('touchstart', this.touchstartHandler, { passive: true });
    document.addEventListener('touchmove', this.touchmoveHandler, { passive: true });
    document.addEventListener('touchend', this.touchendHandler, { passive: true });
    document.addEventListener('touchcancel', this.touchcancelHandler, { passive: true });

    // Add orientation support if available
    if (this._capabilities.hasOrientationSupport) {
      this.orientationHandler = (event: DeviceOrientationEvent) => {
        const data: OrientationEventData = {
          alpha: event.alpha,
          beta: event.beta,
          gamma: event.gamma,
          absolute: event.absolute || false
        };
        this.emitEvent('deviceorientation', data);
      };

      window.addEventListener('deviceorientation', this.orientationHandler, { passive: true });
    }

    this.setConnected(true);
  }

  async cleanup(): Promise<void> {
    if (this.touchstartHandler) {
      document.removeEventListener('touchstart', this.touchstartHandler);
    }
    if (this.touchmoveHandler) {
      document.removeEventListener('touchmove', this.touchmoveHandler);
    }
    if (this.touchendHandler) {
      document.removeEventListener('touchend', this.touchendHandler);
    }
    if (this.touchcancelHandler) {
      document.removeEventListener('touchcancel', this.touchcancelHandler);
    }
    if (this.orientationHandler) {
      window.removeEventListener('deviceorientation', this.orientationHandler);
    }

    this.touchstartHandler = undefined;
    this.touchmoveHandler = undefined;
    this.touchendHandler = undefined;
    this.touchcancelHandler = undefined;
    this.orientationHandler = undefined;

    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    const hasTouch = 'ontouchstart' in window;
    const hasOrientation = 'DeviceOrientationEvent' in window;
    const hasPressure = 'force' in Touch.prototype;

    return {
      canDetectHotplug: false,
      supportsHighPrecisionTiming: true,
      hasOrientationSupport: hasOrientation,
      hasPressureSupport: hasPressure
    };
  }

  async requestOrientationPermission(): Promise<boolean> {
    if (!this._capabilities.hasOrientationSupport) {
      return false;
    }

    // For iOS 13+ devices, request permission
    if (typeof (DeviceOrientationEvent as any).requestPermission === 'function') {
      try {
        const permission = await (DeviceOrientationEvent as any).requestPermission();
        return permission === 'granted';
      } catch (error) {
        console.error('Error requesting device orientation permission:', error);
        return false;
      }
    }

    // For other devices, assume permission is granted
    return true;
  }

  private createTouchEventData(event: TouchEvent): TouchEventData {
    return {
      touches: this.touchListToArray(event.touches),
      changedTouches: this.touchListToArray(event.changedTouches),
      targetTouches: this.touchListToArray(event.targetTouches),
      altKey: event.altKey,
      ctrlKey: event.ctrlKey,
      shiftKey: event.shiftKey,
      metaKey: event.metaKey
    };
  }

  private touchListToArray(touchList: TouchList): TouchPoint[] {
    const touches: TouchPoint[] = [];
    for (let i = 0; i < touchList.length; i++) {
      const touch = touchList[i];
      touches.push({
        identifier: touch.identifier,
        x: touch.clientX,
        y: touch.clientY,
        radiusX: touch.radiusX,
        radiusY: touch.radiusY,
        rotationAngle: touch.rotationAngle,
        force: touch.force
      });
    }
    return touches;
  }
}

