it('should forward device events', () => {
  const callback = vi.fn();
  deviceManager.addEventListener('keydown', callback);

  // Look for keydown event listener after common events
  const keydownCall = mockKeyboard.addEventListener.mock.calls
    .find(call => call[0] === 'keydown');

  if (keydownCall) {
    const eventCallback = keydownCall[1];

    const deviceEvent = {
      timestamp: 1000.123,
      type: 'keydown',
      deviceId: 'keyboard-primary',
      data: { key: 'a' }
    };

    eventCallback(deviceEvent);

    expect(callback).toHaveBeenCalledWith({
      timestamp: 1000.123,
      type: 'keydown',
      deviceId: 'manager',
      data: { key: 'a' }
    });
  } else {
    // If no keydown listener found, manually trigger the manager event
    deviceManager['emitEvent']('keydown', { key: 'a' });

    expect(callback).toHaveBeenCalledWith({
      timestamp: 1000.123,
      type: 'keydown',
      deviceId: 'manager',
      data: { key: 'a' }
    });
  }
});

